const payload = $json.body ?? $json;
const context = payload.contexto ?? payload.context ?? {};
const tracking = payload.tracking ?? {};
const memoria = payload.memoria ?? payload.memory ?? {};

function normalizeObject(value) {
  return String(value ?? '').trim().toLowerCase().replace(/\s+/g, '_');
}

function numberOrDefault(value, fallback = 0) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

const objeto = normalizeObject(payload.objeto ?? payload.object);
const confianza = numberOrDefault(payload.confianza ?? payload.confidence);
const camara = String(payload.camara ?? payload.camera ?? payload.camara_id ?? 'PC-01');
const hora = String(payload.hora ?? payload.detected_at ?? new Date().toISOString());
const box = payload.box ?? null;
const imagen = payload.imagen ?? payload.image_path ?? payload.imagen_url ?? null;

const eventTime = new Date(hora);
const hour = Number.isNaN(eventTime.getTime()) ? new Date().getHours() : eventTime.getHours();
const isNight = hour >= 22 || hour <= 5;

return [
  {
    json: {
      agente: 'AgenteAnalisis',
      version: '0.2.0',
      entrada: {
        objeto,
        confianza,
        camara,
        hora,
        box,
        imagen
      },
      contexto: {
        zona: context.zona ?? context.zone ?? 'sin_zona',
        iluminacion: normalizeObject(context.iluminacion ?? context.lighting ?? 'desconocida'),
        hora_local: hour,
        noche: isNight
      },
      tracking: {
        person_id: tracking.person_id ?? tracking.track_id ?? null,
        velocidad: numberOrDefault(tracking.velocidad ?? tracking.speed),
        permanencia_segundos: numberOrDefault(tracking.permanencia_segundos ?? tracking.loitering_seconds),
        movimiento_erratico: Boolean(tracking.movimiento_erratico ?? tracking.erratic_motion ?? false)
      },
      memoria: {
        eventos_previos_24h: numberOrDefault(memoria.eventos_previos_24h ?? memoria.previous_events_24h),
        alertas_previas_24h: numberOrDefault(memoria.alertas_previas_24h ?? memoria.previous_alerts_24h)
      }
    }
  }
];

const data = $json;
const objeto = data.entrada.objeto;
const confianza = data.entrada.confianza;
const contexto = data.contexto;
const tracking = data.tracking;
const memoria = data.memoria;

const objectBaseScores = {
  gun: 80,
  knife: 60,
  scissors: 40,
  backpack: 18,
  person: 10,
  cell_phone: 5,
  car: 8,
  truck: 8,
  motorcycle: 10
};
const dangerousObjects = new Set(['knife', 'gun', 'scissors']);
let score = 0;
const factores = [];

function add(points, code, detail) {
  score += points;
  factores.push({ code, points, detail });
}

if (!objeto) {
  add(5, 'payload_incompleto', 'No se recibio objeto detectable.');
} else if (Object.prototype.hasOwnProperty.call(objectBaseScores, objeto)) {
  const code = dangerousObjects.has(objeto) ? 'objeto_peligroso' : 'objeto_base';
  add(objectBaseScores[objeto], code, `Objeto detectado: ${objeto}.`);
} else {
  add(8, 'objeto_observado', `Objeto observado sin regla critica: ${objeto}.`);
}

if (confianza >= 0.9) add(10, 'alta_confianza', `Confianza alta: ${confianza}.`);
else if (confianza >= 0.7) add(5, 'confianza_media', `Confianza aceptable: ${confianza}.`);
else add(-10, 'baja_confianza', `Confianza baja: ${confianza}.`);

if (contexto.noche) add(15, 'horario_nocturno', 'Evento detectado en horario nocturno.');
if (['baja', 'oscura', 'low', 'dark'].includes(contexto.iluminacion)) add(10, 'baja_iluminacion', 'Condicion de baja iluminacion.');
if (tracking.velocidad >= 7) add(12, 'movimiento_rapido', `Velocidad elevada: ${tracking.velocidad}.`);
if (tracking.movimiento_erratico) add(15, 'movimiento_erratico', 'Movimiento erratico reportado por tracking.');
if (tracking.permanencia_segundos >= 900) add(25, 'permanencia_sospechosa', 'Permanencia mayor o igual a 15 minutos.');
else if (tracking.permanencia_segundos >= 300) add(10, 'permanencia_media', 'Permanencia mayor o igual a 5 minutos.');
if (memoria.alertas_previas_24h >= 2) add(15, 'historial_alertas', 'La camara/zona tiene alertas recientes.');
if (memoria.eventos_previos_24h >= 10) add(8, 'historial_eventos', 'La camara/zona tiene actividad reciente alta.');

score = Math.max(0, Math.min(100, Math.round(score)));
let riesgo = 'BAJO';
let severidad = 'INFORMATIVA';
if (score >= 80) {
  riesgo = 'CRITICO';
  severidad = 'CRITICA';
} else if (score >= 50) {
  riesgo = 'ALTO';
  severidad = 'ALTA';
} else if (score >= 25) {
  riesgo = 'MEDIO';
  severidad = 'MEDIA';
}

return [
  {
    json: {
      ...data,
      resultado: {
        riesgo,
        nivel_riesgo: riesgo,
        severidad,
        score,
        score_riesgo: Math.round((score / 100) * 10000) / 10000,
        factores,
        algoritmo: 'risk_rules_v1'
      }
    }
  }
];

const data = $json;
const score = data.resultado.score;
const riesgo = data.resultado.riesgo;
const severidad = data.resultado.severidad;

let accion = 'REGISTRAR_EVENTO';
let prioridad = 2;
let notificar = false;
const canales = [];

if (score >= 80) {
  accion = 'ALERTA_CRITICA';
  prioridad = 10;
  notificar = true;
  canales.push('telegram', 'dashboard_realtime');
} else if (score >= 50) {
  accion = 'ENVIAR_ALERTA';
  prioridad = 8;
  notificar = true;
  canales.push('dashboard_realtime');
} else if (score >= 25) {
  accion = 'MONITOREAR';
  prioridad = 5;
} else if (data.entrada.confianza < 0.5) {
  accion = 'IGNORAR_BAJA_CONFIANZA';
  prioridad = 1;
}

return [
  {
    json: {
      status: 'procesado',
      pipeline: ['AgentePercepcion', 'AgenteAnalisis', 'AgenteRiesgo', 'AgenteAccion', 'AgenteMemoria'],
      agente: data.agente,
      version: data.version,
      entrada: data.entrada,
      contexto: data.contexto,
      tracking: data.tracking,
      memoria: data.memoria,
      resultado: data.resultado,
      decision: {
        accion,
        accion_tomada: accion,
        prioridad,
        notificar,
        canales,
        guardar_en_supabase: true,
        requiere_revision_humana: ['ALTO', 'CRITICO'].includes(riesgo)
      },
      persistencia: {
        camara_id: data.entrada.camara,
        objeto: data.entrada.objeto,
        confianza: data.entrada.confianza,
        score_riesgo: data.resultado.score_riesgo,
        nivel_riesgo: data.resultado.nivel_riesgo,
        accion_tomada: accion,
        alertas_previas_24h: data.memoria.alertas_previas_24h,
        detected_at: data.entrada.hora,
        box: data.entrada.box,
        contexto: data.contexto
      },
      mensaje: `${accion}: ${riesgo} con score ${data.resultado.score_riesgo}`,
      siguientes_agentes: {
        tracking: 'pendiente_fase_3',
        prediccion_ml: 'pendiente_fase_7',
        dashboard: 'pendiente_fase_8'
      },
      procesado_en: new Date().toISOString()
    }
  }
];
